head.script:
//==================================================================================================================
// id       : co_203_06_03b
// 이름     : 월별원가계획조회
// 경로     : 회계/관리회계/사업계획/
// 작 성 자 : 오영재
// 작 업 일 : 
// 사용계정 : 내부
// 비고     :
//
// 업로드   :
// 다운로드 : 
// 레포트   :
// 호출     : 
//==================================================================================================================

scwin.load = true;
scwin.memJson = $c.data.getMemInfo();
scwin.privAdmin = $c.gus.cfIsNull(scwin.memJson.privAdmin) ? '' : scwin.memJson.privAdmin;
scwin.today = $c.date.getServerDateTime("yyyyMMdd");
scwin.strFromDate = scwin.today.substring(0, 6);

scwin.wrkNo = "";             // 작업구분코드
scwin.fromDate = "";          // 작업날짜

scwin.vLoginCoCd = $c.gus.cfIsNull(scwin.memJson.coCd) ? '' : scwin.memJson.coCd;   //소속 자회사
scwin.vLoginCoClsCd = $c.gus.cfIsNull(scwin.memJson.coClsCd) ? '' : scwin.memJson.coClsCd;   //회계_회사구분('CO035' : 0:동부 EXPRESS)
scwin.vUserHomeClsCd = $c.gus.cfIsNull(scwin.memJson.userHomeClsCd) ? '' : scwin.memJson.userHomeClsCd;   //사용자소속구분코드
scwin.vCoCd = $c.gus.cfIsNull(scwin.memJson.coCd) ? '' : scwin.memJson.coCd;   //회사코드
scwin.isSubCompany = false;

//hidden
scwin.hid_FromDate = "";
scwin.txtCoClsCd = "";

scwin.onpageload = function () {
    grd_section1.setStyle("display", "none");
    const codeOptions = [
        { grpCd: "CO012", compID: "lc_unit" }
    ];
    // console.log(" codeOptions : "+ JSON.stringify(codeOptions));
    $c.data.setCommonCode(codeOptions);
};

scwin.onUdcCompleted = function () {
    ed_FromDate.setValue(scwin.today.substring(0, 4));
    //debug
    scwin.hid_FromDate = ed_FromDate.getValue();
    scwin.f_LoadVer();
    $c.gus.cfDisableKey();

    scwin.f_setCompanyInfo();
}

scwin.ondataload = function () {
    lc_unit.setSelectedIndex(1);
}

//-------------------------------------------------------------------------
// 자회사 회계 시스템 추가에 따른 설정 
//-------------------------------------------------------------------------
scwin.f_setCompanyInfo = function () {
    // 사용자 구분이 자회사('SA')가 아닌 경우, 소속회사를  '동부 EXPRESS'로  Default set
    if (scwin.vUserHomeClsCd != ACConstants.SUBSIDIARY_USER_HOME_CLS_CD) {
        scwin.vLoginCoCd = ACConstants.CO_CD_DONGBU;
        scwin.vLoginCoClsCd = ACConstants.CO_CLS_CD_DONGBU;
    }

    ed_coCd.setValue(scwin.vLoginCoCd);
    scwin.load = true;
    scwin.f_PopUpCompanyInfo('T');
}

scwin.udc_coCd_cb = function (rtnList) {
    // SET	 
    if (rtnList != null) {
        if (rtnList[0] == "N/A") return;

        //if(ed_coCd.options.hidVal != rtnList[0] ) {
        ed_coCd.setValue(rtnList[0]);	// 코드
        ed_coNm.setValue(rtnList[5]); // 회사명 
        ed_coCd.options.hidVal = rtnList[0];  // 히든값
        scwin.txtCoClsCd = rtnList[1];	// 회사구분   
        //}

    } else {
        ed_coCd.setValue("");
        ed_coNm.setValue("");
        ed_coCd.options.hidVal = "";
        scwin.txtCoClsCd = "";
    }

    if (scwin.txtCoClsCd > ACConstants.CO_CLS_CD_DONGBU) {  	// 자회사 회계 시스템 
        scwin.isSubCompany = true;
    } else {
        scwin.isSubCompany = false;
    }

    if (scwin.load) {
        if ('T' == scwin.privAdmin || !scwin.isSubCompany) { // ADMIN 권한이 있는 경우, 동부 EXPRESS 인 경우 
            $c.gus.cfEnableObjects([ed_coCd, ed_coNm, btn_company]);
        } else {
            $c.gus.cfDisableObjects([ed_coCd, ed_coNm, btn_company]);
        }

        scwin.load = false;
    }
}

//-------------------------------------------------------------------------
// 회사 입력 팝업 
//-------------------------------------------------------------------------
scwin.f_PopUpCompanyInfo = function (pWinCloseTF) {

    udc_coCd.setSelectId("retrieveDongbuGroupCompanyInfo");
    udc_coCd.cfCommonPopUp(
        scwin.udc_coCd_cb
        , ed_coCd.getValue(), ed_coNm.getValue()
        , pWinCloseTF, null, null, null, null
        , null, null, null, null, null);
}

//-------------------------------------------------------------------------
// Ver정보를 가져온다.
//-------------------------------------------------------------------------
scwin.f_LoadVer = function () {
    // 작업구분코드 및 날짜 세팅함수 호출
    scwin.f_setWrkNoFromDate();

    sbm_version.action = "/cm.zz.RetrieveCommonPopupCMD.do?sysCd=CommonEBC" +
        "&queryId=retrieveVersionInfo" +
        "&param1=" + scwin.fromDate;
    //ds_version.Reset();
    $c.sbm.execute(sbm_version);


}

scwin.f_setWrkNoFromDate = function () {
    scwin.fromDate = ed_FromDate.getValue().trim() + "00";
}

//-------------------------------------------------------------------------
// 최종 Ver을 설정
//-------------------------------------------------------------------------
scwin.f_SetFinalVer = function () {
    if (ds_version.getRowCount() < 1) return;

    let index = 0;
    for (i = 0; i < ds_version.getRowCount(); i++) {
        if (ds_version.getCellData(i, "col3") == 1) {
            index = i;
            break;
        }
    }
    lc_version.setSelectedIndex(index);
}

//-------------------------------------------------------------------------
// 실적부서를 구한다.
//-------------------------------------------------------------------------
scwin.f_GetRsltsDept = async function () {

    let ret;
    // 사업여역이 NULL일경우 귀속부서는 필수 입력임
    if (ed_sacctDeptCd.getValue().trim() != "") {
        // 조회조건 필수사항 체크
        ret = await $c.gus.cfValidate([ed_FromDate, ed_sacctDeptCd, lc_version]);
        if (!ret) {
            return;
        }

        sbm_dept.action = "/cm.zz.RetrieveCommonPopupCMD.do?sysCd=ManagementProfitAndLossEBC" +
            "&queryId=retrievePlanComparisonResultsAcctDept" +
            "&param1=" + ed_sacctDeptCd.getValue().trim() +
            "&param2=" + ed_FromDate.getValue().trim() +
            "&param3=" + dma_searchMonthCostPlan.get("lowerDeptIncluYn") +
            "&param4=" + dma_searchMonthCostPlan.get("acctDeptLvl") +
            "&param5=" + dma_searchMonthCostPlan.get("ver") +
            "&param7=" + dma_searchMonthCostPlan.get("coCd");
        // 귀속부서가 NULL일경우 사업영역은 필수임
    } else if (ed_sbizDomCd.getValue().trim() != "") {
        // 조회조건 필수사항 체크
        ret = await $c.gus.cfValidate([ed_FromDate, ed_sbizDomCd, lc_version]);
        if (!ret) {
            return;
        }
        sbm_dept.action = "/cm.zz.RetrieveCommonPopupCMD.do?sysCd=BusinessDomainEBC" +
            "&queryId=retrievePlanComparisonResultsBizDomCd" +
            "&param1=" + ed_sbizDomCd.getValue().trim() +
            "&param3=" + dma_searchMonthCostPlan.get("lowerDeptIncluYn")
    } else {
        $c.gus.cfAlertMsg("부서 혹은 사업영역중 하나는 필수 입력 입니다.");
        return;
    }

    console.log(sbm_dept.action);

    $c.sbm.execute(sbm_dept);
    //ds_dept.Reset();
}

scwin.btn_search_onclick = function (e) {
    scwin.f_GetRsltsDept();
};

scwin.btn_reset_onclick = function (e) {
    $c.gus.cfInitObjects(table1, [ed_FromDate, ed_sacctDeptCd, ed_sacctDeptNm, ed_sbizDomCd, ed_sbizDomNm]);
};


scwin.udc_sacctDeptCd_cb = function (rtnList) {
    if (rtnList != null) {
        if (rtnList[0] == "N/A") return;
        dma_searchMonthCostPlan.set("acctDeptLvl", rtnList[6]);
    } else {
        dma_searchMonthCostPlan.set("acctDeptLvl", 0);
    }
    scwin.f_resultPopUp(ed_sacctDeptCd, ed_sacctDeptNm, rtnList);
}
scwin.udc_sbizDomCd_cb = function (rtnList) {
    if (rtnList != null) {
        if (rtnList[0] == "N/A") return;
        dma_searchMonthCostPlan.set("acctDeptLvl", rtnList[6]);
    } else {
        dma_searchMonthCostPlan.set("acctDeptLvl", 0);
    }
    scwin.f_resultPopUp(ed_sbizDomCd, ed_sbizDomNm, rtnList);
}

//-------------------------------------------------------------------------
// 각 Argument에 따른 PopUp을 호출 한다.
// 1:조회->부서, 2:조회->사업영역
// code변수는 각 항목별 검색요청 값이다.
//-------------------------------------------------------------------------
scwin.f_openPopUp = function (orgObjCd, orgObjNm, select_code, flag) {

    let param_yy = ed_FromDate.getValue().trim();
    let param = "";

    // POPUP 돋보기 클릭시는 모든값을 조회 할 수 있도록 한다. flag:ALL일 경우는 돋보기 클릭한것임.
    if (flag == "ALL") {
        cd = "";
        nm = "";
    } else {
        cd = orgObjCd.getValue();
        nm = orgObjNm.getValue();
    }

    switch (select_code) {
        // 조회조건용 수금부서 PopUp 호출(물류 귀속부서만 POPUP에 포함)
        case '1':
            param = param_yy + ",,,,,,,,," + ed_coCd.getValue();
            udc_sacctDeptCd.setSelectId("retrieveAcctDeptCdInfo");
            udc_sacctDeptCd.cfCommonPopUp(
                scwin.udc_sacctDeptCd_cb
                , cd, nm, 'T', null, null, null, null, param, null, null, null, null);

            break;
        // 조회조건용 사업영역
        case '2':
            udc_sbizDomCd.setSelectId("retrieveBizDomCdInfo");
            udc_sbizDomCd.cfCommonPopUp(
                scwin.udc_sbizDomCd_cb
                , cd, nm, "T", null, null, null, null, "1,,,,,", "450", "500", null, null); // 사업영역

            break;
        default:
            $c.gus.cfAlertMsg("잘못된 Function호출 입니다. 관리자에게 문의하시기 바랍니다.");
            break;
    }
}

//-------------------------------------------------------------------------
// PopUp창에서 사용되는 각 Cd,Nm에 대해서 POPUP표시 및 해당 값이 없을경우는 코드와 이름을 초기화 시킨다.
// flag값이 CD:코드변경이 없으면 POPUP안뛰움, NM:무조건 POPUP뛰움
//-------------------------------------------------------------------------
scwin.f_CheckPopUp = function (orgObjCd, orgObjNm, select_code, flag) {
    if (flag == "CD") {
        if (orgObjCd.getValue() == orgObjCd.options.hidVal) {
            return;
        } else {
            orgObjNm.setValue("");
        }
    } else {
        if (orgObjNm.getValue() == orgObjNm.options.hidVal) {
            return;
        } else {
            orgObjCd.setValue("");
        }
    }

    if (orgObjCd.getValue().trim() != "" || flag == "NM") {
        if (orgObjNm.getValue().trim() != "" || flag == "CD") {
            orgObjCd.setValue(orgObjCd.getValue().trim());
            orgObjNm.setValue(orgObjNm.getValue().trim());
            scwin.f_openPopUp(orgObjCd, orgObjNm, select_code, "NO");
        }
    } else {
        orgObjNm.setValue("");
        orgObjCd.setValue("");
        orgObjCd.options.hidVal = "";
    }
}

//-------------------------------------------------------------------------
// 팝업결과
//-------------------------------------------------------------------------

scwin.f_resultPopUp = function (orgObjCd, orgObjNm, rtnList) {
    if (rtnList != null) {
        if (rtnList[0] == "N/A") return;
        orgObjCd.setValue(rtnList[0]); // 코드값
        orgObjNm.setValue(rtnList[1]); // 코드명
        orgObjCd.options.hidVal = rtnList[0];   // HIDDEN 코드값
        orgObjNm.options.hidVal = rtnList[1];   // HIDDEN 코드명
    } else {
        orgObjCd.setValue("");
        orgObjNm.setValue("");
        orgObjCd.options.hidVal = "";
        orgObjNm.options.hidVal = "";
    }
}

scwin.sbm_version_submitdone = function (e) {
    scwin.f_SetFinalVer();
}
scwin.sbm_version_submiterror = function (e) { }

scwin.sbm_searchMonthCostPlan_submitdone = function (e) {

    //원본 데이터를 ds_deptProfitLossOriginal에 백업
    let originalData = ds_MonthCostPlan.getAllJSON();
    ds_MonthCostPlan_org.setJSON(originalData);

    //cfHideDSWaitMsg(gr_MonthCostPlan);
    if (ds_MonthCostPlan.getRowCount() == 0) {
        $c.gus.cfAlertMsg(MSG_CM_ERR_003);
        scwin.f_ClearPaging();
    } else {
        scwin.f_MoveToPage(1);
        scwin.f_CalPercent();
    }
    grd_section1.setStyle("display", "block");

    scwin.f_SetGridFormat(1);
    btn_trigger1.addClass("btn pt-blue");
    btn_trigger2.removeClass("pt-blue");

    ed_totalRows.setValue(ds_MonthCostPlan.getRowCount());
    scwin.f_changeUnit();
}
scwin.sbm_searchMonthCostPlan_submiterror = function (e) { }

//-------------------------------------------------------------------------
// 페이지정보를 초기화한다.
//-------------------------------------------------------------------------
scwin.f_ClearPaging = function () {
    //pagingIndex.setValue("");
};

//-------------------------------------------------------------------------
// 페이지정보를 초기화한다.
//-------------------------------------------------------------------------
scwin.f_MoveToPage = function (pageNum) {
    scwin.f_changeUnit();
    scwin.f_SetGridFormat(pageNum);
    //scwin.f_DisplayPaging(pageNum);
};

scwin.sbm_dept_submitdone = function (e) {
    ds_dept.sort('col1', 0);
    scwin.f_Retrieve();
}
scwin.sbm_dept_submiterror = function (e) {
    $c.gus.cfAlertMsg(e.responseJSON.resultDataSet[1].Msg);
}

//-------------------------------------------------------------------------
// 조회
//-------------------------------------------------------------------------
scwin.f_Retrieve = async function () {

    let ret;
    dma_searchMonthCostPlan.set("distYn", "1"); // 배부포함여부를 항상 포함으로 고정함.(2006.04.13)
    if (ed_sacctDeptCd.getValue().trim() != "") {
        // 조회조건 필수사항 체크
        ret = await $c.gus.cfValidate([ed_FromDate, ed_sacctDeptCd, lc_version, ed_coCd]);
        if (!ret) {
            return;
        }
    } else if (ed_sbizDomCd.getValue().trim() != "") {
        // 조회조건 필수사항 체크
        ret = await $c.gus.cfValidate([ed_FromDate, ed_sbizDomCd, lc_version, ed_coCd]);
        if (!ret) {
            return;
        }
    } else {
        $c.gus.cfAlertMsg("부서 혹은 사업영역중 하나는 필수 입력 입니다.");
        return;
    }

    // 귀속부서로 조회 할 경우
    if (ed_sacctDeptCd.getValue().trim() != "") {
        dma_searchMonthCostPlan.set("acctDeptCd", lc_acctDeptCd.getValue());
        dma_searchMonthCostPlan.set("bizDomCd", "");
        // 사업영역으로 조회 할 경우
    } else if (ed_sbizDomCd.getValue().trim() != "") {
        dma_searchMonthCostPlan.set("bizDomCd", lc_acctDeptCd.getValue());
        dma_searchMonthCostPlan.set("acctDeptCd", "");
    } else {
        $c.gus.cfAlertMsg("부서 혹은 사업영역중 하나는 필수 입력 입니다.");
        return;
    }

    $c.sbm.execute(sbm_searchMonthCostPlan);
    //tr_searchMonthCostPlan.Post();

}

scwin.f_Export = async function () {
    let ret;
    ret = await $c.win.confirm("Excel로 다운로드 하시겠습니까?");

    if (ret) {
        let sheetTitle = "월별원가계획조회_" + ed_sacctDeptNm.getValue().trim() + "_" + ed_FromDate.getValue().trim() + "_ver_" + lc_version.getValue();
        const gridId = gr_MonthCostPlan;
        const infoArr = [];
        const options = {
            fileName: sheetTitle + ".xlsx",    // + ".xls",
            sheetName: sheetTitle
        };

        $c.data.downloadGridViewExcel(gridId, options, infoArr);
    }
}
scwin.ed_FromDate_onblur = function (e) {
    scwin.f_LoadVer();
};

scwin.udc_sacctDeptCd_onblurCodeEvent = function (e) {
    scwin.f_CheckPopUp(ed_sacctDeptCd, ed_sacctDeptNm, '1', 'CD');
};

scwin.udc_sacctDeptCd_onblurNameEvent = function (e) {
    scwin.f_CheckPopUp(ed_sacctDeptCd, ed_sacctDeptNm, '1', 'NM');
};

scwin.udc_sbizDomCd_onblurCodeEvent = function (e) {
    scwin.f_CheckPopUp(ed_sbizDomCd, ed_sbizDomNm, '2', 'CD');
};

scwin.udc_sbizDomCd_onblurNameEvent = function (e) {
    scwin.f_CheckPopUp(ed_sbizDomCd, ed_sbizDomNm, '2', 'NM');
};

scwin.udc_sbizDomCd_onclickEvent = function (e) {
    scwin.f_openPopUp(ed_sbizDomCd, ed_sbizDomNm, '2', 'ALL');
};

scwin.lc_unit_onchange = function (info) {
    scwin.f_changeUnit();
};

//-------------------------------------------------------------------------
// 그리드의 단위를 변경한다.
//-------------------------------------------------------------------------
scwin.f_changeUnit = function () {

    if (lc_unit.getValue() == "01") {
        scwin.f_changeUnitAmt(1);
    } else if (lc_unit.getValue() == "02") {
        scwin.f_changeUnitAmt(1000);
    } else if (lc_unit.getValue() == "03") {
        scwin.f_changeUnitAmt(1000000);
    } else if (lc_unit.getValue() == "04") {
        scwin.f_changeUnitAmt(100000000);
    }
}

//-------------------------------------------------------------------------
// 그리드의 단위를 변경한다.
//-------------------------------------------------------------------------
scwin.f_changeUnitAmt = function (unitAmt) {
    if (!ds_MonthCostPlan_org || ds_MonthCostPlan_org.getRowCount() === 0) {
        return;
    }

    let calculatedData = ds_MonthCostPlan_org.getAllJSON();

    const cols = ["amt", "jan", "feb", "mar", "apr", "may", "jun", "jul", "aug", "sep", "oct", "nov", "dec", "halfYy", "halfYy2"];


    for (let i = 0; i < calculatedData.length; i++) {
        let rowData = calculatedData[i];

        for (const colId of cols) {
            if (rowData.hasOwnProperty(colId)) {
                //console.log("colId =>" + colId);
                let originalValue = parseFloat(rowData[colId] || 0);
                rowData[colId] = Math.round(originalValue / unitAmt);
                ds_MonthCostPlan.setCellData(i, colId, rowData[colId]);
            }
        }
    }
    //ds_MonthCostPlan.setJSON(calculatedData); origin 에서 복사 했기에 비율이 없다.
};


scwin.f_CalPercent = function () {

    if (!ds_MonthCostPlan_org || ds_MonthCostPlan_org.getRowCount() === 0) {
        return;
    }
    //2026.02.23 계산식 변경 요청에 따른 연산 수정
    for (var i = 0; i < ds_MonthCostPlan.getRowCount(); i++) {

        var amtPercent = Math.round((ds_MonthCostPlan_org.getCellData(i, "amt") / ds_MonthCostPlan_org.getCellData(0, "amt") * 100) * 100) / 100;
        var janPercent = Math.round((ds_MonthCostPlan_org.getCellData(i, "jan") / ds_MonthCostPlan_org.getCellData(0, "jan") * 100) * 100) / 100;
        var febPercent = Math.round((ds_MonthCostPlan_org.getCellData(i, "feb") / ds_MonthCostPlan_org.getCellData(0, "feb") * 100) * 100) / 100;
        var marPercent = Math.round((ds_MonthCostPlan_org.getCellData(i, "mar") / ds_MonthCostPlan_org.getCellData(0, "mar") * 100) * 100) / 100;
        var aprPercent = Math.round((ds_MonthCostPlan_org.getCellData(i, "apr") / ds_MonthCostPlan_org.getCellData(0, "apr") * 100) * 100) / 100;
        var mayPercent = Math.round((ds_MonthCostPlan_org.getCellData(i, "may") / ds_MonthCostPlan_org.getCellData(0, "may") * 100) * 100) / 100;
        var junPercent = Math.round((ds_MonthCostPlan_org.getCellData(i, "jun") / ds_MonthCostPlan_org.getCellData(0, "jun") * 100) * 100) / 100;
        var julPercent = Math.round((ds_MonthCostPlan_org.getCellData(i, "jul") / ds_MonthCostPlan_org.getCellData(0, "jul") * 100) * 100) / 100;
        var augPercent = Math.round((ds_MonthCostPlan_org.getCellData(i, "aug") / ds_MonthCostPlan_org.getCellData(0, "aug") * 100) * 100) / 100;
        var sepPercent = Math.round((ds_MonthCostPlan_org.getCellData(i, "sep") / ds_MonthCostPlan_org.getCellData(0, "sep") * 100) * 100) / 100;
        var octPercent = Math.round((ds_MonthCostPlan_org.getCellData(i, "oct") / ds_MonthCostPlan_org.getCellData(0, "oct") * 100) * 100) / 100;
        var novPercent = Math.round((ds_MonthCostPlan_org.getCellData(i, "nov") / ds_MonthCostPlan_org.getCellData(0, "nov") * 100) * 100) / 100;
        var decPercent = Math.round((ds_MonthCostPlan_org.getCellData(i, "dec") / ds_MonthCostPlan_org.getCellData(0, "dec") * 100) * 100) / 100;
        var halfYyPercent = Math.round((ds_MonthCostPlan_org.getCellData(i, "halfYy") / ds_MonthCostPlan_org.getCellData(0, "halfYy") * 100) * 100) / 100;
        var halfYy2Percent = Math.round((ds_MonthCostPlan_org.getCellData(i, "halfYy2") / ds_MonthCostPlan_org.getCellData(0, "halfYy2") * 100) * 100) / 100;

        if (isFinite(amtPercent)) {
            ds_MonthCostPlan.setCellData(i, "amtPercent", amtPercent);
        } else {
            ds_MonthCostPlan.setCellData(i, "amtPercent", 0);
        }

        if (isFinite(janPercent)) {
            ds_MonthCostPlan.setCellData(i, "janPercent", janPercent);
        } else {
