};

//-------------------------------------------------------------------------
// 그리드 포맷설정
//-------------------------------------------------------------------------
scwin.f_SetGridFormat = function (pageNum) {
    if ($c.gus.cfIsNull(pageNum)) pageNum = 1;

    // 상반기/하반기 컬럼 ID 목록
    let halfYy1 = [
        "jan", "janPercent",
        "feb", "febPercent",
        "mar", "marPercent",
        "apr", "aprPercent",
        "may", "mayPercent",
        "jun", "junPercent",
        "halfYy", "halfYyPercent"
    ];

    let halfYy2 = [
        "jul", "julPercent",
        "aug", "augPercent",
        "sep", "sepPercent",
        "oct", "octPercent",
        "nov", "novPercent",
        "dec", "decPercent",
        "halfYy2", "halfYy2Percent"
    ];


    let showCols, hideCols;

    if (pageNum == 1) {
        showCols = halfYy1;
        hideCols = halfYy2;
    } else {
        hideCols = halfYy1;
        showCols = halfYy2;
    }

    // setColumnVisible API로 각 컬럼을 제어
    showCols.forEach(colId => {
        gr_MonthCostPlan.setColumnVisible(colId, true);
    });
    hideCols.forEach(colId => {
        gr_MonthCostPlan.setColumnVisible(colId, false);
    });
};

scwin.btn_pageNum1_onclick = function (e) {
    scwin.f_SetGridFormat(1);
    btn_trigger1.addClass("btn pt-blue");
    btn_trigger2.removeClass("pt-blue");
};

scwin.btn_pageNum2_onclick = function (e) {
    scwin.f_SetGridFormat(2);
    btn_trigger1.removeClass("pt-blue");
    btn_trigger2.addClass("btn pt-blue");
};
scwin.udc_coCd_onclickEvent = function (e) {
